#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        if (N % 2 == 1) {
            printf("-1\n");
        } else {
            for (int i = N; i >= 1; --i) {
                printf("%d", i);
                if (i > 1) printf(" ");
            }
            printf("\n");
        }
    }
    return 0;
}

