import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        n = int(data[idx]); idx += 1
        if n % 2 == 1:
            out_lines.append('-1')
        else:
            out_lines.append(' '.join(str(i) for i in range(n, 0, -1)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

